import path from"node:path";import{BrowserPlatform}from"./types.js";function folder(e){switch(e){case BrowserPlatform.LINUX_ARM:case BrowserPlatform.LINUX:return"linux64";case BrowserPlatform.MAC_ARM:return"mac-arm64";case BrowserPlatform.MAC:return"mac-x64";case BrowserPlatform.WIN32:return"win32";case BrowserPlatform.WIN64:return"win64"}}export function resolveDownloadUrl(e,r,o="https://storage.googleapis.com/chrome-for-testing-public"){return`${o}/${resolveDownloadPath(e,r).join("/")}`}export function resolveDownloadPath(e,r){return[r,folder(e),`chrome-headless-shell-${folder(e)}.zip`]}export function relativeExecutablePath(e,r){switch(e){case BrowserPlatform.MAC:case BrowserPlatform.MAC_ARM:return path.join("chrome-headless-shell-"+folder(e),"chrome-headless-shell");case BrowserPlatform.LINUX_ARM:case BrowserPlatform.LINUX:return path.join("chrome-headless-shell-linux64","chrome-headless-shell");case BrowserPlatform.WIN32:case BrowserPlatform.WIN64:return path.join("chrome-headless-shell-"+folder(e),"chrome-headless-shell.exe")}}export{resolveBuildId,compareVersions}from"./chrome.js";